import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {

  const LOG_COUNT  = 50;
  const DENY_RATIO = 0.40;
  const DEVICE_NAME = 'FGT-600F-PROD';
  const DEVICE_ID   = 'FGT6001234567890';
  const VDOM = 'root';

  const INTERNAL_SUBNETS = [
    { net: '10.0.1',   intf: 'port1',  role: 'lan' },
    { net: '10.0.2',   intf: 'port2',  role: 'lan' },
    { net: '10.0.10',  intf: 'port3',  role: 'dmz' },
    { net: '172.16.5', intf: 'ssl.root', role: 'vpn' },
  ];

  const EXTERNAL_SUBNETS = [
    { net: '203.0.113', intf: 'wan1', role: 'wan' },
    { net: '198.51.100', intf: 'wan1', role: 'wan' },
    { net: '192.0.2',   intf: 'wan2', role: 'wan' },
  ];

  const TRAFFIC_PROFILES = [
    { app: 'HTTPS',   dport: 443,  proto: 6,  service: 'HTTPS',   appcat: 'Web.Client',     risk: 1 },
    { app: 'HTTP',    dport: 80,   proto: 6,  service: 'HTTP',    appcat: 'Web.Client',     risk: 1 },
    { app: 'DNS',     dport: 53,   proto: 17, service: 'DNS',     appcat: 'Network.Service', risk: 1 },
    { app: 'SSH',     dport: 22,   proto: 6,  service: 'SSH',     appcat: 'Remote.Access',  risk: 3 },
    { app: 'FTP',     dport: 21,   proto: 6,  service: 'FTP',     appcat: 'File.Sharing',   risk: 4 },
    { app: 'SMTP',    dport: 25,   proto: 6,  service: 'SMTP',    appcat: 'Email',          risk: 3 },
    { app: 'MS-SQL',  dport: 1433, proto: 6,  service: 'MS-SQL',  appcat: 'Database',       risk: 4 },
    { app: 'RDP',     dport: 3389, proto: 6,  service: 'RDP',     appcat: 'Remote.Access',  risk: 5 },
    { app: 'NTP',     dport: 123,  proto: 17, service: 'NTP',     appcat: 'Network.Service', risk: 1 },
    { app: 'IMAP',    dport: 143,  proto: 6,  service: 'IMAP',    appcat: 'Email',          risk: 2 },
    { app: 'unknown', dport: 4444, proto: 6,  service: 'tcp/4444', appcat: 'unknown',       risk: 5 },
    { app: 'ICMP',    dport: 0,    proto: 1,  service: 'PING',    appcat: 'Network.Service', risk: 1 },
  ];

  const ALLOW_POLICIES = [
    'Allow-Outbound-Web', 'Allow-DNS', 'Allow-Internal-SSH',
    'Allow-VPN-Access', 'Allow-NTP', 'Allow-DMZ-HTTPS',
  ];

  const DENY_POLICIES = [
    'Deny-Inbound-RDP', 'Deny-SQL-External', 'Deny-FTP-WAN',
    'Block-Suspicious', 'Implicit-Deny',
  ];

  const IPS_SIGNATURES = [
    { sig: 'MS.Windows.SMB.Server.Trans2.Remote.Code.Execution', sev: 'critical', cve: 'CVE-2017-0144' },
    { sig: 'ET.MALWARE.Cobalt.Strike.Beacon', sev: 'high', cve: '' },
    { sig: 'HTTP.URI.SQL.Injection', sev: 'medium', cve: '' },
    { sig: 'SSH.Brute.Force.Login', sev: 'high', cve: '' },
    { sig: 'Log4j.JNDI.Injection', sev: 'critical', cve: 'CVE-2021-44228' },
    { sig: 'RDP.BlueKeep.Exploit', sev: 'critical', cve: 'CVE-2019-0708' },
    { sig: 'FTP.Bounce.Attack', sev: 'low', cve: '' },
  ];

  const VPN_USERS = [
    'alice.smith', 'bob.johnson', 'carol.white', 'dave.brown',
    'eve.jones', 'frank.davis', 'grace.miller', 'henry.wilson',
  ];

  const COUNTRIES = ['United States', 'United Kingdom', 'Germany', 'China', 'Russia', 'Brazil', 'Reserved'];

  function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }
  function pick(arr) { return arr[randomInt(0, arr.length - 1)]; }
  function randomIp(subnet) { return `${subnet.net}.${randomInt(1, 254)}`; }
  function pad(n) { return n < 10 ? '0' + n : '' + n; }

  function fmtDate(ts) {
    return `${ts.getFullYear()}-${pad(ts.getMonth()+1)}-${pad(ts.getDate())}`;
  }
  function fmtTime(ts) {
    return `${pad(ts.getHours())}:${pad(ts.getMinutes())}:${pad(ts.getSeconds())}`;
  }
  function eventTime(ts) {
    return Math.floor(ts.getTime() / 1000).toString();
  }

  function buildTrafficLog(index, ts) {
    const isDeny   = Math.random() < DENY_RATIO;
    const profile  = pick(TRAFFIC_PROFILES);
    const blocked  = isDeny || profile.risk >= 5;
    const action   = blocked ? pick(['deny', 'server-rst', 'client-rst']) : 'accept';
    const policy   = blocked ? pick(DENY_POLICIES) : pick(ALLOW_POLICIES);
    const policyid = blocked ? randomInt(100, 199) : randomInt(1, 99);

    let src, dst, srcintf, dstintf;
    if (blocked && Math.random() < 0.6) {
      src = pick(EXTERNAL_SUBNETS); dst = pick(INTERNAL_SUBNETS);
      srcintf = src.intf; dstintf = dst.intf;
    } else {
      src = pick(INTERNAL_SUBNETS); dst = pick(EXTERNAL_SUBNETS);
      srcintf = src.intf; dstintf = dst.intf;
    }

    const srcip  = randomIp(src);
    const dstip  = randomIp(dst);
    const sport  = randomInt(1024, 65535);
    const dport  = profile.dport;
    const proto  = profile.proto;
    const sentbyte = blocked ? randomInt(40, 120) : randomInt(500, 500000);
    const rcvdbyte = blocked ? 0 : randomInt(500, 800000);
    const sentpkt  = blocked ? randomInt(1, 3) : randomInt(5, 2000);
    const rcvdpkt  = blocked ? 0 : randomInt(5, 3000);
    const duration = blocked ? 0 : randomInt(1, 3600);
    const sessionid = randomInt(100000, 999999);
    const logid    = '0000000013';
    const utmaction = blocked ? 'block' : 'allow';
    const srccountry = src.role === 'wan' ? pick(COUNTRIES) : 'Reserved';
    const dstcountry = dst.role === 'wan' ? pick(COUNTRIES) : 'Reserved';

    const level = blocked ? 'warning' : 'notice';

    return `date=${fmtDate(ts)} time=${fmtTime(ts)} devname="${DEVICE_NAME}" devid="${DEVICE_ID}" logid="${logid}" type="traffic" subtype="forward" level="${level}" vd="${VDOM}" eventtime=${eventTime(ts)} srcip=${srcip} srcport=${sport} srcintf="${srcintf}" srcintfrole="${src.role}" dstip=${dstip} dstport=${dport} dstintf="${dstintf}" dstintfrole="${dst.role}" policyid=${policyid} policyname="${policy}" sessionid=${sessionid} proto=${proto} action="${action}" policytype="policy" service="${profile.service}" dstcountry="${dstcountry}" srccountry="${srccountry}" trandisp="snat" duration=${duration} sentbyte=${sentbyte} rcvdbyte=${rcvdbyte} sentpkt=${sentpkt} rcvdpkt=${rcvdpkt} appcat="${profile.appcat}" app="${profile.app}" applist="default" utmaction="${utmaction}" countapp=1`;
  }

  function buildIPSLog(ts) {
    const sig = pick(IPS_SIGNATURES);
    const src = pick(EXTERNAL_SUBNETS);
    const dst = pick(INTERNAL_SUBNETS);
    const srcip = randomIp(src);
    const dstip = randomIp(dst);
    const sport = randomInt(1024, 65535);
    const dport = pick([80, 443, 22, 445, 3389, 1433]);
    const sessionid = randomInt(100000, 999999);
    const logid = '0419016384';
    const srccountry = pick(COUNTRIES.filter(c => c !== 'Reserved'));

    return `date=${fmtDate(ts)} time=${fmtTime(ts)} devname="${DEVICE_NAME}" devid="${DEVICE_ID}" logid="${logid}" type="utm" subtype="ips" level="alert" vd="${VDOM}" eventtime=${eventTime(ts)} severity="${sig.sev}" srcip=${srcip} srccountry="${srccountry}" dstip=${dstip} srcintf="${src.intf}" dstintf="${dst.intf}" sessionid=${sessionid} action="dropped" proto=6 service="tcp/${dport}" policyid=${randomInt(1,50)} attack="${sig.sig}" srcport=${sport} dstport=${dport} direction="${Math.random() < 0.7 ? 'incoming' : 'outgoing'}" attackid=${randomInt(10000, 99999)} profile="default-ips" ref="http://www.fortiguard.com/encyclopedia/ips" incidentserialno=${randomInt(100000000, 999999999)} msg="${sig.sig}: Exploit attempt blocked"${sig.cve ? ` cve="${sig.cve}"` : ''}`;
  }

  function buildVPNLog(ts) {
    const user = pick(VPN_USERS);
    const remoteip = randomIp(pick(EXTERNAL_SUBNETS));
    const tunnel = `ssl.${VDOM}`;
    const success = Math.random() < 0.8;
    const action = success ? 'ssl-login-succeed' : 'ssl-login-fail';
    const level = success ? 'notice' : 'warning';
    const logid = '0101039424';
    const msg = success
      ? `SSL VPN ${user} login from ${remoteip}. Virtual IP assigned: 172.16.5.${randomInt(10, 250)}`
      : `SSL VPN ${user} login failed from ${remoteip}. Reason: bad credentials`;

    return `date=${fmtDate(ts)} time=${fmtTime(ts)} devname="${DEVICE_NAME}" devid="${DEVICE_ID}" logid="${logid}" type="event" subtype="vpn" level="${level}" vd="${VDOM}" eventtime=${eventTime(ts)} logdesc="SSL VPN" action="${action}" tunneltype="ssl-web" tunnelid=${randomInt(1000, 9999)} remip=${remoteip} user="${user}" group="VPN-Users" dst_host="N/A" reason="${success ? 'login' : 'sslvpn_login_denied'}" msg="${msg}"`;
  }

  function buildSystemLog(ts) {
    const events = [
      { action: 'login', level: 'information', msg: `Admin admin logged in from ${randomIp(pick(INTERNAL_SUBNETS))} using GUI` },
      { action: 'logout', level: 'information', msg: `Admin admin logged out from ${randomIp(pick(INTERNAL_SUBNETS))}` },
      { action: 'config-change', level: 'warning', msg: `Admin admin changed firewall policy policyid=${randomInt(1,200)}` },
      { action: 'ha-switch', level: 'critical', msg: 'HA switch-over: primary unit detected as failed' },
      { action: 'interface-down', level: 'warning', msg: `Interface ${pick(['wan1','wan2','port3'])} went down` },
    ];
    const ev = pick(events);
    const logid = '0100032003';
    return `date=${fmtDate(ts)} time=${fmtTime(ts)} devname="${DEVICE_NAME}" devid="${DEVICE_ID}" logid="${logid}" type="event" subtype="system" level="${ev.level}" vd="${VDOM}" eventtime=${eventTime(ts)} logdesc="System Event" action="${ev.action}" msg="${ev.msg}"`;
  }

  const logLines = [];
  const summary  = { total: LOG_COUNT, byType: {}, byAction: {} };

  for (let i = 0; i < LOG_COUNT; i++) {
    const now = new Date();
    const offset = Math.floor((i / LOG_COUNT) * 3600 * 1000);
    const ts = new Date(now.getTime() - 3600000 + offset);

    const roll = Math.random();
    let line;
    if (roll < 0.60) {
      line = buildTrafficLog(i, ts);
    } else if (roll < 0.80) {
      line = buildIPSLog(ts);
    } else if (roll < 0.92) {
      line = buildVPNLog(ts);
    } else {
      line = buildSystemLog(ts);
    }
    logLines.push(line);
    const typeMatch  = line.match(/type="([^"]+)"/);
    const subtypeMatch = line.match(/subtype="([^"]+)"/);
    const actionMatch  = line.match(/action="([^"]+)"/);
    const logType   = typeMatch  ? typeMatch[1]  : 'unknown';
    const logSubtype = subtypeMatch ? subtypeMatch[1] : 'unknown';
    const action    = actionMatch ? actionMatch[1] : 'unknown';
    const key = `${logType}/${logSubtype}`;
    summary.byType[key]       = (summary.byType[key] || 0) + 1;
    summary.byAction[action]  = (summary.byAction[action] || 0) + 1;
  }

  console.log(`Generated ${LOG_COUNT} Fortinet FortiGate log entries.`);
  console.log(`  By type: ${JSON.stringify(summary.byType)}`);
  console.log(`  By action: ${JSON.stringify(summary.byAction)}`);

  return { logLines, summary };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { logsClient } from '@dynatrace-sdk/client-classic-environment-v2';

const BATCH_SIZE = 20;

function parseKV(line) {
  const result = {};
  const re = /(\w+)="([^"]*)"|([\w.]+)=([^\s]+)/g;
  let m;
  while ((m = re.exec(line)) !== null) {
    if (m[1] !== undefined) {
      result[m[1]] = m[2];
    } else {
      result[m[3]] = m[4];
    }
  }
  return result;
}

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_fortinet_logs');
  const logLines  = genResult.logLines;
  const summary   = genResult.summary;

  const logEntries = [];
  for (const line of logLines) {
    const kv = parseKV(line);
    const action = kv.action || 'unknown';
    const logType = kv.type || 'unknown';
    const subtype = kv.subtype || 'unknown';

    let severity = 'INFO';
    const level = kv.level || '';
    if (level === 'warning' || level === 'alert') severity = 'WARN';
    else if (level === 'critical' || level === 'emergency') severity = 'ERROR';
    else if (level === 'error') severity = 'ERROR';

    const entry = {
      'content':              line,
      'log.source':           'fortinet-fortigate',
      'log.tag':              'demo-log-generator',
      'severity':             severity,
      'source_vendor':        'Fortinet',
      'source_product':       'FortiGate',
      'env':                  'demo',
      'hostname':             kv.devname || 'FGT-600F-PROD',
      'fortinet.devname':     kv.devname || '',
      'fortinet.devid':       kv.devid || '',
      'fortinet.logid':       kv.logid || '',
      'fortinet.type':        logType,
      'fortinet.subtype':     subtype,
      'fortinet.level':       level,
      'fortinet.action':      action,
      'fortinet.srcip':       kv.srcip || '',
      'fortinet.dstip':       kv.dstip || '',
      'fortinet.srcport':     parseInt(kv.srcport) || 0,
      'fortinet.dstport':     parseInt(kv.dstport) || 0,
      'fortinet.srcintf':     kv.srcintf || '',
      'fortinet.dstintf':     kv.dstintf || '',
      'fortinet.proto':       parseInt(kv.proto) || 0,
      'fortinet.policyid':    parseInt(kv.policyid) || 0,
      'fortinet.policyname':  kv.policyname || '',
      'fortinet.service':     kv.service || '',
      'fortinet.app':         kv.app || '',
      'fortinet.appcat':      kv.appcat || '',
      'fortinet.utmaction':   kv.utmaction || '',
      'fortinet.sentbyte':    parseInt(kv.sentbyte) || 0,
      'fortinet.rcvdbyte':    parseInt(kv.rcvdbyte) || 0,
      'fortinet.sentpkt':     parseInt(kv.sentpkt) || 0,
      'fortinet.rcvdpkt':     parseInt(kv.rcvdpkt) || 0,
      'fortinet.duration':    parseInt(kv.duration) || 0,
      'fortinet.srccountry':  kv.srccountry || '',
      'fortinet.dstcountry':  kv.dstcountry || '',
    };

    if (logType === 'utm' && subtype === 'ips') {
      entry['fortinet.attack']    = kv.attack || '';
      entry['fortinet.severity']  = kv.severity || '';
      entry['fortinet.attackid']  = parseInt(kv.attackid) || 0;
      if (kv.cve) entry['fortinet.cve'] = kv.cve;
    }
    if (logType === 'event' && subtype === 'vpn') {
      entry['fortinet.user']       = kv.user || '';
      entry['fortinet.tunneltype'] = kv.tunneltype || '';
      entry['fortinet.reason']     = kv.reason || '';
      entry['fortinet.remip']      = kv.remip || '';
    }

    logEntries.push(entry);
  }

  let ingested = 0;
  const errors = [];
  for (let i = 0; i < logEntries.length; i += BATCH_SIZE) {
    const batch = logEntries.slice(i, i + BATCH_SIZE);
    try {
      await logsClient.storeLog({
        type: 'application/json; charset=utf-8',
        body: batch,
      });
      ingested += batch.length;
      console.log(`Batch ${Math.floor(i/BATCH_SIZE)+1}: ingested ${batch.length} entries.`);
    } catch (e) {
      const msg = `Batch ${Math.floor(i/BATCH_SIZE)+1} failed: ${e.message}`;
      console.error(msg);
      errors.push(msg);
    }
  }

  console.log(`Ingested ${ingested}/${logEntries.length} Fortinet log entries into Grail.`);
  return { totalIngested: ingested, totalAttempted: logEntries.length, summary, errors };
}

import { execution } from '@dynatrace-sdk/automation-utils';

function parseKV(line) {
  const result = {};
  const re = /(\w+)="([^"]*)"|([\w.]+)=([^\s]+)/g;
  let m;
  while ((m = re.exec(line)) !== null) {
    if (m[1] !== undefined) { result[m[1]] = m[2]; }
    else { result[m[3]] = m[4]; }
  }
  return result;
}

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_fortinet_logs');
  const logLines  = genResult.logLines;

  const byType    = {};
  const byAction  = {};
  const byPolicy  = {};
  const byAttack  = {};
  let   blockedTraffic = 0;
  let   allowedTraffic = 0;
  let   ipsEvents      = 0;
  let   vpnEvents      = 0;

  for (const line of logLines) {
    const kv = parseKV(line);
    const key = `${kv.type || '?'}/${kv.subtype || '?'}`;
    byType[key]              = (byType[key] || 0) + 1;
    byAction[kv.action || '?'] = (byAction[kv.action || '?'] || 0) + 1;
    if (kv.policyname) byPolicy[kv.policyname] = (byPolicy[kv.policyname] || 0) + 1;
    if (kv.attack)     byAttack[kv.attack]     = (byAttack[kv.attack] || 0) + 1;
    if (kv.type === 'traffic') {
      if (kv.action === 'accept') allowedTraffic++; else blockedTraffic++;
    }
    if (kv.type === 'utm' && kv.subtype === 'ips') ipsEvents++;
    if (kv.type === 'event' && kv.subtype === 'vpn') vpnEvents++;
  }

  const report = {
    total:           logLines.length,
    byType,
    byAction,
    byPolicy,
    byAttack,
    trafficAllowed:  allowedTraffic,
    trafficBlocked:  blockedTraffic,
    ipsEvents,
    vpnEvents,
    validationResult: logLines.length > 0
      ? `PASS - Generated ${logLines.length} entries. Traffic: ${allowedTraffic} allow / ${blockedTraffic} deny. IPS: ${ipsEvents}. VPN: ${vpnEvents}.`
      : 'FAIL - No log entries generated',
  };

  console.log(`Fortinet analysis: ${report.validationResult}`);
  return report;
}
